SELECT f.*, u.nick_name AS follow_nick_name
FROM user_follow f
LEFT JOIN user_info u ON f.follow_user_id = u.user_id
WHERE f.user_id = #{userId}
ORDER BY f.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}

